func Test_BatchCrawlStreamEvents(t *testing.T) {
	// Batch crawl stream produces expected Page and Complete events
	var engineConfig pkg.CrawlConfig
	if err := json.Unmarshal([]byte(`{"max_concurrent":2}`), &engineConfig); err != nil {
		t.Fatalf("config parse failed: %v", err)
	}
	engine, createErr := pkg.CreateEngine(&engineConfig)
	if createErr != nil {
		t.Fatalf("create handle failed: %v", createErr)
	}
	urlsBase := os.Getenv("MOCK_SERVER_BATCH_CRAWL_STREAM_EVENTS")
	if urlsBase == "" {
		urlsBase = os.Getenv("MOCK_SERVER_URL") + "/fixtures/batch_crawl_stream_events"
	}
	var urls []string
	for _, p := range []string{`/page1`, `/page2`, `/page3`} {
		if strings.HasPrefix(p, "http") {
			urls = append(urls, p)
		} else {
			urls = append(urls, urlsBase+p)
		}
	}
	stream, err := pkg.BatchCrawlStream(engine, urls)
	if err != nil {
		t.Fatalf("call failed: %v", err)
	}
	var chunks []pkg.CrawlEvent
	for chunk := range stream {
		chunks = append(chunks, chunk)
	}
	assert.GreaterOrEqual(t, len(chunks), 4, "expected >= 4")
	assert.True(t, func() bool {
		for _, e := range chunks {
			if _, _ok := e.(pkg.CrawlEventPage); _ok {
				return true
			}
		}
		return false
	}(), "expected true")
	assert.True(t, func() bool {
		for _, e := range chunks {
			if _, _ok := e.(pkg.CrawlEventComplete); _ok {
				return true
			}
		}
		return false
	}(), "expected true")
}

